AND TO_CHAR(A.POINT_TRT_DT, 'YYYYMMDDHH24MISS') BETWEEN #{strtDt} || '000000' AND #{endDt} || '235959'
AND B.USER_ID = #{searchVal}
AND A.REQUEST_KEY = #{searchVal}
AND B.SVC_CNTR_NO = #{searchVal}
ORDER BY CRET_DT DESC
